import{_ as o,o as a,c as t,a2 as s}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse('{"title":"ADR-037 — Shared surface-site type, deferred shared <SurfaceMap> component","description":"","frontmatter":{},"headers":[],"relativePath":"adr/ADR-037.md","filePath":"adr/ADR-037.md"}'),r={name:"adr/ADR-037.md"};function i(n,e,c,d,l,h){return a(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="adr-037-—-shared-surface-site-type-deferred-shared-surfacemap-component" tabindex="-1">ADR-037 — Shared <code>surface-site</code> type, deferred shared <code>&lt;SurfaceMap&gt;</code> component <a class="header-anchor" href="#adr-037-—-shared-surface-site-type-deferred-shared-surfacemap-component" aria-label="Permalink to &quot;ADR-037 — Shared `surface-site` type, deferred shared `&lt;SurfaceMap&gt;` component&quot;">​</a></h1><blockquote><p>Status · Accepted (closes RFC-012 OQ-1) Date · 2026-05-09 (back-filled from v0.4.0 implementation) Closes · RFC-012 OQ-1 (&quot;Generic SurfaceMap component, or independent /mars + /moon?&quot;) TA anchor · §components/surface-routes Related ADRs · ADR-019 (ajv schema), ADR-038 (per-body 2D projection), ADR-039 (cross-link contract)</p></blockquote><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>PRD-009 specified <code>/mars</code> as a peer of <code>/moon</code>: same panel pattern, same site catalogue shape, same 3D + 2D toggle. RFC-012 OQ-1 asked whether the two routes should share a generic <code>&lt;SurfaceMap&gt;</code> component or stay independent.</p><p>Two stages were considered:</p><ol><li><strong>Shared TYPE</strong> — pull the <code>MarsSite</code> + <code>MoonSite</code> interfaces out into a single <code>SurfaceSite</code> discriminated union with a <code>kind: &#39;surface&#39; | &#39;orbiter&#39;</code> field. Both routes alias the type so the JSON schema is shared, validate-data covers both with one ruleset, and panel rendering can share helpers.</li><li><strong>Shared COMPONENT</strong> — pull the actual 3D scene + 2D map + panel-mount logic into a <code>&lt;SurfaceMap site={…}&gt;</code> component used by both routes.</li></ol><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><h3 id="shared-type-—-shipped-in-v0-4-0" tabindex="-1">Shared TYPE — shipped in v0.4.0 <a class="header-anchor" href="#shared-type-—-shipped-in-v0-4-0" aria-label="Permalink to &quot;Shared TYPE — shipped in v0.4.0&quot;">​</a></h3><p><code>src/types/surface-site.ts</code> defines the canonical <code>SurfaceSite</code> interface plus the <code>kind: &#39;surface&#39; | &#39;orbiter&#39;</code> discriminator. <code>src/types/mars-site.ts</code> and <code>src/types/moon-site.ts</code> both <code>export { SurfaceSite as MarsSite }</code> / <code>MoonSite</code> for ergonomic per-route imports. Shared schema in <code>static/data/schemas/surface-site.schema.json</code> validates both <code>mars-sites.json</code> and <code>moon-sites.json</code>.</p><p>This gives V1 the data-layer + validation benefits without forcing the routes to share visual code while their 2D projections diverge (see ADR-038).</p><h3 id="shared-component-—-deferred-to-v0-6-0" tabindex="-1">Shared COMPONENT — deferred to v0.6.0 <a class="header-anchor" href="#shared-component-—-deferred-to-v0-6-0" aria-label="Permalink to &quot;Shared COMPONENT — deferred to v0.6.0&quot;">​</a></h3><p>The shared <code>&lt;SurfaceMap&gt;</code> component refactor is tracked as <strong>issue #42</strong> on the v0.6.0 milestone. /mars and /moon currently have independent <code>+page.svelte</code> files that share helpers via <code>src/lib/</code> (mostly site-state derivations + data fetchers) but not the rendering loop.</p><p>Rationale for deferring:</p><ul><li>The Moon&#39;s orthographic-pair 2D projection (near + far disc) and Mars&#39;s equirectangular projection (single rectangular map) are visually different enough that a single component would need either two render paths or a per-body adaptor — that&#39;s the same complexity as keeping two routes.</li><li>/mars shipped with rover traverses (RFC-012 OQ-6) which /moon does not have. Adding traverses to a shared component would increase its API surface.</li><li>The cross-link contract (ADR-039) operates at the data-layer + URL level, not the component level, so it&#39;s unaffected by the routing split.</li></ul><p>When Apollo / Chandrayaan / Chang&#39;e site overlays land for /moon and the visual pattern stabilises, the shared-component refactor becomes worthwhile. Until then, two <code>+page.svelte</code> files of ~1100 lines each is cheaper than the abstraction.</p><h2 id="rationale" tabindex="-1">Rationale <a class="header-anchor" href="#rationale" aria-label="Permalink to &quot;Rationale&quot;">​</a></h2><p>The data-layer abstraction (shared TYPE + schema) gives 80% of the maintenance benefit (one schema, one validator, one set of cross-link helpers) at 20% of the abstraction cost. The component-layer abstraction would force a single rendering path for two routes whose visual designs are still diverging — premature.</p><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ul><li><strong>Single shared component for both routes</strong> — see &quot;deferred&quot; above. Premature.</li><li><strong>No shared type</strong> — keeps full per-route freedom but duplicates the JSON schema and the cross-link helpers. Rejected because the data-layer cost is real.</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><p><strong>Positive:</strong></p><ul><li>One source of truth for surface-site shape across <code>/mars</code> and <code>/moon</code>.</li><li>One schema validates both sites JSON files; ajv catches drift.</li><li>Cross-link helpers (<code>/mars</code> ↔ <code>/missions</code>, <code>/moon</code> ↔ <code>/missions</code>) share a single implementation per ADR-039.</li><li>Two route files keep visual freedom for as long as projection / overlay design is moving.</li></ul><p><strong>Negative:</strong></p><ul><li>Two <code>+page.svelte</code> files of similar shape — visible duplication that future contributors may try to factor out.</li><li>The <code>&lt;SurfaceMap&gt;</code> shared component is now an outstanding refactor ticket (#42 on v0.6.0).</li></ul><h2 id="implementation-notes" tabindex="-1">Implementation notes <a class="header-anchor" href="#implementation-notes" aria-label="Permalink to &quot;Implementation notes&quot;">​</a></h2><ul><li><code>src/types/surface-site.ts</code> — canonical <code>SurfaceSite</code> interface + discriminator.</li><li><code>src/types/mars-site.ts</code>, <code>src/types/moon-site.ts</code> — re-exports.</li><li><code>static/data/schemas/surface-site.schema.json</code> — shared schema.</li><li><code>scripts/validate-data.ts</code> validates both <code>mars-sites.json</code> and <code>moon-sites.json</code> against the same schema.</li><li><code>src/routes/mars/+page.svelte</code>, <code>src/routes/moon/+page.svelte</code> — independent route files.</li><li>Component-shared refactor tracked as #42 (v0.6.0 milestone).</li></ul>',26)])])}const m=o(r,[["render",i]]);export{u as __pageData,m as default};
